package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testValueOf() {
        // Mocking the Predefined enum
        CSVFormat.Predefined predefined = mock(CSVFormat.Predefined.class);
        when(predefined.getFormat()).thenReturn(CSVFormat.DEFAULT);

        // Mocking the valueOf method of Predefined enum
        when(CSVFormat.Predefined.valueOf("DEFAULT")).thenReturn(predefined);

        // Testing the valueOf method
        CSVFormat result = CSVFormat.valueOf("DEFAULT");
        assertEquals(CSVFormat.DEFAULT, result);
    }
}
